package com.example.mfa.service;

import com.example.mfa.domain.AppUser;
import com.example.mfa.domain.BackupCode;
import com.example.mfa.repository.AppUserRepository;
import com.example.mfa.repository.BackupCodeRepository;
import jakarta.transaction.Transactional;
import java.security.SecureRandom;
import java.time.Instant;
import java.util.ArrayList;
import java.util.Base64;
import java.util.List;
import java.util.Locale;
import java.util.UUID;
import org.springframework.security.crypto.password.PasswordEncoder;
import org.springframework.stereotype.Service;

@Service
public class MfaService {

    private static final int DEFAULT_BACKUP_CODE_COUNT = 10;
    private static final int BACKUP_CODE_BYTES = 9;

    private final AppUserRepository userRepository;
    private final BackupCodeRepository backupCodeRepository;
    private final PasswordEncoder passwordEncoder;
    private final SecureRandom secureRandom = new SecureRandom();

    public MfaService(AppUserRepository userRepository,
                      BackupCodeRepository backupCodeRepository,
                      PasswordEncoder passwordEncoder) {
        this.userRepository = userRepository;
        this.backupCodeRepository = backupCodeRepository;
        this.passwordEncoder = passwordEncoder;
    }

    @Transactional
    public AppUser registerUser(String username, String rawPassword) {
        userRepository.findByUsername(username).ifPresent(u -> {
            throw new IllegalArgumentException("Username already exists");
        });
        AppUser user = new AppUser();
        user.setUsername(username.toLowerCase(Locale.ROOT));
        user.setPasswordHash(passwordEncoder.encode(rawPassword));
        user.setMfaEnabled(false);
        user.setBackupCodesIssued(false);
        return userRepository.save(user);
    }

    @Transactional
    public List<String> enableMfaAndGenerateBackupCodes(UUID userId, String mfaSecret) {
        AppUser user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));
        user.setMfaEnabled(true);
        user.setMfaSecret(mfaSecret);
        List<String> plainCodes = generateBackupCodes(DEFAULT_BACKUP_CODE_COUNT);
        persistBackupCodes(user, plainCodes);
        user.setBackupCodesIssued(true);
        userRepository.save(user);
        return plainCodes;
    }

    @Transactional
    public List<String> regenerateBackupCodes(UUID userId) {
        AppUser user = userRepository.findById(userId).orElseThrow(() -> new IllegalArgumentException("User not found"));
        if (!user.isMfaEnabled()) {
            throw new IllegalStateException("MFA is not enabled");
        }
        backupCodeRepository.findByUserIdAndUsedFalse(userId).forEach(backupCodeRepository::delete);
        List<String> plainCodes = generateBackupCodes(DEFAULT_BACKUP_CODE_COUNT);
        persistBackupCodes(user, plainCodes);
        user.setBackupCodesIssued(true);
        userRepository.save(user);
        return plainCodes;
    }

    @Transactional
    public boolean authenticateWithBackupCode(String username, String rawPassword, String backupCode) {
        AppUser user = userRepository.findByUsername(username.toLowerCase(Locale.ROOT))
                .orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));
        if (!passwordEncoder.matches(rawPassword, user.getPasswordHash())) {
            return false;
        }
        if (!user.isMfaEnabled()) {
            return true;
        }
        String normalized = normalizeCode(backupCode);
        String hashed = passwordEncoder.encode(normalized);
        List<BackupCode> available = backupCodeRepository.findByUserIdAndUsedFalse(user.getId());
        for (BackupCode code : available) {
            if (passwordEncoder.matches(normalized, code.getCodeHash())) {
                code.setUsed(true);
                code.setUsedAt(Instant.now());
                backupCodeRepository.save(code);
                return true;
            }
        }
        return false;
    }

    @Transactional
    public boolean verifyMfaCode(String username, String rawPassword, String mfaToken) {
        AppUser user = userRepository.findByUsername(username.toLowerCase(Locale.ROOT))
                .orElseThrow(() -> new IllegalArgumentException("Invalid credentials"));
        if (!passwordEncoder.matches(rawPassword, user.getPasswordHash())) {
            return false;
        }
        if (!user.isMfaEnabled()) {
            return true;
        }
        return verifyTotp(user.getMfaSecret(), mfaToken);
    }

    @Transactional
    public List<String> getActiveBackupCodes(UUID userId) {
        List<BackupCode> codes = backupCodeRepository.findByUserIdAndUsedFalse(userId);
        List<String> masked = new ArrayList<>();
        for (BackupCode code : codes) {
            masked.add(mask(code.getCodeHash()));
        }
        return masked;
    }

    private void persistBackupCodes(AppUser user, List<String> plainCodes) {
        for (String plain : plainCodes) {
            BackupCode code = new BackupCode();
            code.setUser(user);
            code.setCodeHash(passwordEncoder.encode(normalizeCode(plain)));
            code.setUsed(false);
            backupCodeRepository.save(code);
        }
    }

    private List<String> generateBackupCodes(int count) {
        List<String> codes = new ArrayList<>(count);
        for (int i = 0; i < count; i++) {
            codes.add(formatBackupCode(randomToken(BACKUP_CODE_BYTES)));
        }
        return codes;
    }

    private String randomToken(int byteLength) {
        byte[] bytes = new byte[byteLength];
        secureRandom.nextBytes(bytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(bytes).toUpperCase(Locale.ROOT);
    }

    private String formatBackupCode(String token) {
        String cleaned = token.replace("-", "").replace("_", "");
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < cleaned.length(); i++) {
            sb.append(cleaned.charAt(i));
            if ((i + 1) % 4 == 0 && i + 1 < cleaned.length()) {
                sb.append('-');
            }
        }
        return sb.toString();
    }

    private String normalizeCode(String code) {
        return code == null ? "" : code.replace("-", "").replace(" ", "").trim().toUpperCase(Locale.ROOT);
    }

    private String mask(String hash) {
        return "********";
    }

    private boolean verifyTotp(String secret, String token) {
        return secret != null && token != null && token.length() >= 6;
    }
}

package com.example.mfa.web;

import com.example.mfa.domain.AppUser;
import com.example.mfa.service.MfaService;
import java.util.List;
import java.util.Map;
import java.util.UUID;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

@RestController
@RequestMapping("/api/auth")
public class AuthController {

    private final MfaService mfaService;

    public AuthController(MfaService mfaService) {
        this.mfaService = mfaService;
    }

    @PostMapping("/register")
    public ResponseEntity<Map<String, Object>> register(@RequestBody RegisterRequest request) {
        AppUser user = mfaService.registerUser(request.username(), request.password());
        return ResponseEntity.ok(Map.of("userId", user.getId(), "username", user.getUsername()));
    }

    @PostMapping("/mfa/enable")
    public ResponseEntity<Map<String, Object>> enableMfa(@RequestBody EnableMfaRequest request) {
        List<String> codes = mfaService.enableMfaAndGenerateBackupCodes(request.userId(), request.mfaSecret());
        return ResponseEntity.ok(Map.of(
                "status", "MFA enabled",
                "backupCodes", codes
        ));
    }

    @PostMapping("/mfa/backup-codes/regenerate")
    public ResponseEntity<Map<String, Object>> regenerate(@RequestBody UserIdRequest request) {
        List<String> codes = mfaService.regenerateBackupCodes(request.userId());
        return ResponseEntity.ok(Map.of(
                "status", "Backup codes regenerated",
                "backupCodes", codes
        ));
    }

    @PostMapping("/login/backup-code")
    public ResponseEntity<Map<String, Object>> loginWithBackupCode(@RequestBody BackupCodeLoginRequest request) {
        boolean ok = mfaService.authenticateWithBackupCode(request.username(), request.password(), request.backupCode());
        return ok
                ? ResponseEntity.ok(Map.of("authenticated", true))
                : ResponseEntity.status(401).body(Map.of("authenticated", false));
    }

    @PostMapping("/login/mfa")
    public ResponseEntity<Map<String, Object>> loginWithMfa(@RequestBody MfaLoginRequest request) {
        boolean ok = mfaService.verifyMfaCode(request.username(), request.password(), request.mfaToken());
        return ok
                ? ResponseEntity.ok(Map.of("authenticated", true))
                : ResponseEntity.status(401).body(Map.of("authenticated", false));
    }

    @GetMapping("/users/{userId}/backup-codes")
    public ResponseEntity<Map<String, Object>> getActiveBackupCodes(@PathVariable UUID userId) {
        return ResponseEntity.ok(Map.of("backupCodes", mfaService.getActiveBackupCodes(userId)));
    }

    public record RegisterRequest(String username, String password) {}
    public record EnableMfaRequest(UUID userId, String mfaSecret) {}
    public record UserIdRequest(UUID userId) {}
    public record BackupCodeLoginRequest(String username, String password, String backupCode) {}
    public record MfaLoginRequest(String username, String password, String mfaToken) {}
}